// Dedup safety net — filter out already-processed emails
// The Outlook Trigger tracks new-since-last-poll automatically,
// but this prevents reprocessing if trigger re-delivers an email.
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedIds) staticData.processedIds = [];

const items = $input.all();
const newItems = items.filter(item => !staticData.processedIds.includes(item.json.id));

console.log(`Received ${items.length} emails, ${newItems.length} new (${items.length - newItems.length} already processed)`);

if (newItems.length === 0) return [];
return newItems;

// Extract email details and parse request type from subject
const email = $input.first().json;
const subject = email.subject || '';

// Determine request type from subject line pattern
// Check Re: prefix FIRST (follow-ups), then Modified/Cancelled, else New
let requestType = 'New';
if (/^Re:\s/i.test(subject)) {
  requestType = 'Follow-up';
} else if (/^STR\s*\(Modified\)/i.test(subject)) {
  requestType = 'Modified';
} else if (/^STR\s*\(Cancell?ed\)/i.test(subject)) {
  requestType = 'Cancelled';
}

// Parse confirmId and tripCode from subject (works for all types including Re:)
const confirmIdMatch = subject.match(/Confirm\s*ID[:\s]+(\d+)/i);
const confirmId = confirmIdMatch ? confirmIdMatch[1] : '';
const tripCodeMatch = subject.match(/\|\s*([A-Z0-9]+(?:@[A-Z0-9]+)?)\s*\|/i);
const tripCode = tripCodeMatch ? tripCodeMatch[1] : '';

console.log(`Processing [${requestType}]: ${subject}`);
console.log(`  Confirm ID: ${confirmId}, Trip Code: ${tripCode}`);

return [{
  json: {
    messageId: email.id,
    subject: email.subject,
    receivedDateTime: email.receivedDateTime,
    hasAttachments: email.hasAttachments,
    requestType: requestType,
    confirmId: confirmId,
    tripCode: tripCode
  }
}];

// Build a minimal row for Cancelled or Follow-up trip requests
// No PDF processing needed — just Confirm ID, status, and email timestamp
const item = $input.first().json;
const receivedDateTime = item.receivedDateTime || '';
const requestType = item.requestType || 'Cancelled';

// Convert ISO date to EST format
let emailReceived = '';
if (receivedDateTime) {
  const d = new Date(receivedDateTime);
  emailReceived = d.toLocaleString('en-US', { timeZone: 'America/New_York', month: '2-digit', day: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit', hour12: true });
}

console.log(`Formatting ${requestType} row: Confirm ID ${item.confirmId}`);

return [{
  json: {
    emailReceived: emailReceived,
    pdfLink: '',
    requestType: requestType,
    confirmId: item.confirmId || '',
    tripCode: item.tripCode || '',
    todaysDate: '',
    overnightTrip: '',
    startDate: '',
    endDate: '',
    startTime: '',
    endTime: '',
    destination: '',
    schoolName: '',
    address: '',
    atsDbn: '',
    district: '',
    region: '',
    requester: '',
    phone1: '',
    phone2: '',
    studentInitials: '',
    studentId: '',
    dob: '',
    medicalNeeds: '',
    textTemplate: '',
    tripLiaison: '',
    tripLiaisonEmail: '',
    tripLiaisonPhone: ''
  }
}];

// Display the extracted trip fields for monitoring
const data = $input.first().json;
const trip = data.tripFields || {};
const studentCount = (data.students || []).length;

console.log(`Trip: ${trip.confirmId} | ${trip.tripCode} | ${trip.destination}`);
console.log(`Students: ${studentCount}`);

return [{
  json: {
    confirmId: trip.confirmId || '',
    tripCode: trip.tripCode || '',
    destination: trip.destination || '',
    schoolName: trip.schoolName || '',
    startDate: trip.startDate || '',
    endDate: trip.endDate || '',
    startTime: trip.startTime || '',
    endTime: trip.endTime || '',
    overnightTrip: trip.overnightTrip || '',
    studentCount: studentCount,
    pdfLink: data.driveUrl || '',
    pdfFilename: data.pdfFilename || '',
    // Pass through full data for next nodes
    _fullResponse: data
  }
}];

// Trip Liaison lookup table
const LIAISONS = [
  { name: 'Samantha Liang',  email: 'slaing@health.nyc.gov',     phone: '(929)-468-5680', districts: [19, 20, 23, 32] },
  { name: 'Samiyrah Hudson', email: 'shudson1@health.nyc.gov',   phone: '(929)-468-5826', districts: [7, 8, 9, 10] },
  { name: 'William Lolagne', email: 'wlolagne@health.nyc.gov',   phone: '(929)-468-5507', districts: [13, 14, 15, 16] },
  { name: 'Tiara Lowder',    email: 'tlowder@health.nyc.gov',    phone: '(929)-468-5788', districts: [24, 25, 26, 30] },
  { name: 'Joseph Weidman',  email: 'JWeideman@schools.nyc.gov', phone: '(347)-697-3179', districts: [5, 6] },
];
const D75_LOW  = { name: 'Natalie Veriguete', email: 'NVeriguete@schools.nyc.gov', phone: '(929)-404-1926' };
const D75_HIGH = { name: 'Tracey Bolden',     email: 'tbolden1@health.nyc.gov',    phone: '(347)-534-7078' };

function lookupLiaison(schoolName, district) {
  const distNum = parseInt(district, 10);
  if (isNaN(distNum)) return null;
  const isCitywide = (schoolName || '').includes('@');
  if (isCitywide) {
    if (distNum >= 1 && distNum <= 12) return D75_LOW;
    if (distNum >= 13 && distNum <= 23) return D75_HIGH;
  }
  return LIAISONS.find(l => l.districts.includes(distNum)) || null;
}

// Build single row with students as comma-separated arrays
const item = $input.first().json;
const data = item._fullResponse || item;
const tripFields = data.tripFields || {};
const students = data.students || [];
const pdfLink = data.driveUrl || item.driveUrl || '';
const receivedDateTime = $('Set Attachment Info').first().json.receivedDateTime || '';

// Convert ISO date to EST format
let emailReceived = '';
if (receivedDateTime) {
  const d = new Date(receivedDateTime);
  emailReceived = d.toLocaleString('en-US', { timeZone: 'America/New_York', month: '2-digit', day: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit', hour12: true });
}

// Get requestType from Log Email Details (New or Modified)
const requestType = $('Log Email Details').first().json.requestType || 'New';
const confirmId = tripFields.confirmId || $('Log Email Details').first().json.confirmId || '';

// Text template for liaison texting
let textTemplate = '';
if (tripFields.startDate) {
  const dp = tripFields.startDate.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if (dp) {
    const dateObj = new Date(parseInt(dp[3]), parseInt(dp[1]) - 1, parseInt(dp[2]));
    const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
    const dayName = days[dateObj.getDay()];
    const shortDate = `${parseInt(dp[1])}/${parseInt(dp[2])}`;
    const studentCount = students.length;
    const meds = students.map(s => s.medicalNeeds || '').filter(Boolean).join('; ') || 'None reported';
    textTemplate = `Trip Coverage for ${dayName} ${shortDate}\nSchool: ${tripFields.schoolName || 'N/A'}\nAddress: ${tripFields.address || 'N/A'}\nTrip Hours: ${tripFields.startTime || 'N/A'} \u2013 ${tripFields.endTime || 'N/A'}\nTrip Destination: ${tripFields.destination || 'N/A'}\nTrip Confirmation # ${confirmId || 'N/A'}\n${studentCount} student(s)\nMeds: ${meds}`;
  }
}

// Trip Liaison lookup
const liaison = lookupLiaison(tripFields.schoolName || '', tripFields.district || '');

console.log(`Formatting ${students.length} student(s) as arrays [${requestType}]`);

return [{
  json: {
    emailReceived: emailReceived,
    pdfLink: pdfLink,
    requestType: requestType,
    confirmId: confirmId,
    tripCode: tripFields.tripCode || $('Log Email Details').first().json.tripCode || '',
    todaysDate: tripFields.todaysDate || '',
    overnightTrip: tripFields.overnightTrip || '',
    startDate: tripFields.startDate || '',
    endDate: tripFields.endDate || '',
    startTime: tripFields.startTime || '',
    endTime: tripFields.endTime || '',
    destination: tripFields.destination || '',
    schoolName: tripFields.schoolName || '',
    address: tripFields.address || '',
    atsDbn: tripFields.atsDbn || '',
    district: tripFields.district || '',
    region: tripFields.region || '',
    requester: tripFields.requester || '',
    phone1: tripFields.phone1 || 'Not Listed',
    phone2: tripFields.phone2 || 'Not Listed',
    studentInitials: students.map(s => s.initials || '').join(', '),
    studentId: students.map(s => s.studentId || '').join(', '),
    dob: students.map(s => s.dob || '').join(', '),
    medicalNeeds: students.map(s => s.medicalNeeds || '').join(', '),
    textTemplate: textTemplate,
    tripLiaison: liaison ? liaison.name : '',
    tripLiaisonEmail: liaison ? liaison.email : '',
    tripLiaisonPhone: liaison ? liaison.phone : ''
  }
}];

// Mark this email as processed so it won't be re-processed next run
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedIds) staticData.processedIds = [];

const messageId = $('Log Email Details').first().json.messageId;
if (messageId && !staticData.processedIds.includes(messageId)) {
  staticData.processedIds.push(messageId);
  // Keep only last 200 IDs to prevent unbounded growth
  if (staticData.processedIds.length > 200) {
    staticData.processedIds = staticData.processedIds.slice(-200);
  }
}

console.log(`Marked ${messageId} as processed (${staticData.processedIds.length} total tracked)`);
return $input.all();

// Log the processing failure details
const result = $input.first().json;
const emailInfo = $('Set Attachment Info').first().json;

console.error(`FAILED: ${emailInfo.emailSubject}`);
console.error(`Error: ${result.error || 'Unknown error'}`);

return [{
  json: {
    status: 'FAILED',
    emailSubject: emailInfo.emailSubject,
    messageId: emailInfo.messageId,
    error: result.error || 'Unknown processing error',
    elapsed: result.elapsed || '',
    timestamp: new Date().toISOString()
  }
}];
